#!/bin/bash
set -e

SUCCESS=0
FAILED=0
FAILED_JOBS=""

add_job() {
  local num="$1"
  local fire="$2"
  local cid="$3"
  local tok="$4"
  local end="$5"
  local q="$6"
  
  local name="watch:${cid:0:16}"
  local msg="Run market watcher for: ${q}

bash /home/node/.openclaw/workspace/trading/market_watcher.sh '${cid}' '${tok}' '${end}' '${q}'

If output contains TRADED: -> notify Philipp on Telegram with details
If output contains ALERT: -> notify Philipp on Telegram
Everything else -> stay silent."

  echo "[$num/63] Adding: $name ($q)"
  
  if openclaw cron add \
    --name "$name" \
    --at "$fire" \
    --message "$msg" \
    --session "isolated" \
    --announce \
    --timeout-seconds 120 \
    --keep-after-run 2>&1; then
    SUCCESS=$((SUCCESS + 1))
    echo "  ✓ Success"
  else
    FAILED=$((FAILED + 1))
    FAILED_JOBS="$FAILED_JOBS $num"
    echo "  ✗ FAILED"
  fi
}

